#include <bits/stdc++.h>
using namespace std;
int main(){int n;cin>>n;vector<vector<int>>g(n,vector<int>(n,0));int dx[]={0,1,0,-1},dy[]={1,0,-1,0};int x=0,y=0,d=0;for(int v=1;v<=n*n;v++){g[x][y]=v;int nx=x+dx[d],ny=y+dy[d];if(nx<0||ny<0||nx>=n||ny>=n||g[nx][ny]!=0){d=(d+1)%4;nx=x+dx[d];ny=y+dy[d];}x=nx;y=ny;}string out;for(int i=0;i<n;i++){for(int j=0;j<n;j++){out+=to_string(g[i][j]);out+=(j+1<n?' ':'\n');}}cout<<out;}
